def get_notes():
user_id = request.args.get("userId")
notes = mongo.db.notes.find({"userId": user_id})
return jsonify([{
"_id": str(note["_id"]),
"text": note["text"],
} for note in notes])

@app.route("/api/images", methods=["POST"])
def add_image():
user_id = request.form["userId"]
image = request.files["file"].read()
mongo.db.images.insert_one({"userId": user_id, "data": image})
return jsonify("Image uploaded successfully")

@app.route("/api/images", methods=["GET"])
def get_images():
user_id = request.args.get("userId")
images = mongo.db.images.find({"userId": user_id})
return jsonify([{
"_id": str(image["_id"]),
"data": image["data"].decode("utf-8"),
} for image in images])

